import heapq

def func(lists, k):
    # Count frequencies of each number across all lists
    freq = {}
    for lst in lists:
        for num in lst:
            freq[num] = freq.get(num, 0) + 1

    # Use a min-heap to keep track of the top k elements
    # Heap will store tuples of (-frequency, number) to simulate max-heap behavior
    heap = []

    for num, count in freq.items():
        if len(heap) < k:
            heapq.heappush(heap, (-count, num))
        else:
            # If current count is greater than the smallest count in heap
            if count > -heap[0][0]:
                heapq.heapreplace(heap, (-count, num))

    # Extract the numbers from the heap
    result = [num for _, num in heap]
    return result

