def max_Prime_Factors(n):
    if n < 2:
        return None

    # Handle 2 separately
    while n % 2 == 0:
        n //= 2

    # Check for odd factors starting from 3
    factor = 3
    while factor * factor <= n:
        while n % factor == 0:
            n //= factor
        factor += 2

    # If n is now greater than 1, it is a prime factor
    if n > 1:
        return n

    return factor

