def find_missing(arr):
    """
    Finds the missing number in a sorted array of consecutive integers.
    Assumes the array starts from 1 and contains no duplicates.
    """
    if not arr:
        return 1

    # Check if the first element is 1
    if arr[0] != 1:
        return arr[0] - 1

    # Iterate through the array to find the gap
    for i in range(1, len(arr)):
        if arr[i] != arr[i - 1] + 1:
            return arr[i - 1] + 1

    # If no gap is found, the missing number is the next one after the last element
    return arr[-1] + 1

