def is_undulating(s: str) -> bool:
    """
    Check if the given string represents an undulating number.
    An undulating number is one where adjacent digits alternate between increasing and decreasing.
    """
    if len(s) < 2:
        return False

    for i in range(1, len(s)):
        prev_digit = int(s[i - 1])
        curr_digit = int(s[i])

        if prev_digit == curr_digit:
            return False

        if i == 1:
            continue

        # Check if the pattern alternates
        if (prev_digit > curr_digit) == (s[i - 2] > s[i - 1]):
            return False

    return True

