def snake_to_camel(snake_case_string):
    if not snake_case_string:
        return snake_case_string

    parts = snake_case_string.split('_')
    if len(parts) == 1:
        return parts[0].capitalize()

    result = parts[0].capitalize()
    for part in parts[1:]:
