def longest_subseq_with_diff_one(arr, k):
    """
    Find the length of the longest subsequence such that the difference between adjacent elements is 1.
    The subsequence does not need to be contiguous.

    :param arr: List of integers
    :param k: The difference between adjacent elements in the subsequence (default is 1)
    :return: Length of the longest subsequence
    """
    if not arr:
        return 0

    # Dictionary to store the length of the longest subsequence ending at each number
    dp = {}

    for num in arr:
        # Check if num - k exists in dp
        if num - k in dp:
            dp[num] = dp[num - k] + 1
        else:
            # If num - k doesn't exist, start a new subsequence
            dp[num] = 1

    # The result is the maximum value in dp
    return max(dp.values())

